approach1.code:
.nav {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 1rem;
  background: #222;
  color: #fff;
  padding: 12px 16px;
  border-radius: 8px;
}
.logo { font-weight: 700; }
.links {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  list-style: none;
  padding: 0;
  margin: 0;
}
.links a { color: #fff; text-decoration: none; }
.links a:focus-visible,
.cta:focus-visible {
  outline: 3px solid #93c5fd;
  outline-offset: 3px;
}
.cta {
  margin-left: auto;
  background: #e63946;
  color: #fff;
  text-decoration: none;
  padding: 6px 12px;
  border-radius: 6px;
  font-weight: 600;
}
@media (max-width: 480px) {
  .links { justify-content: center; width: 100%; }
  .cta { margin-left: 0; text-align: center; }
}

approach2.code:
.nav {
  display: flex;
  align-items: center;
  gap: 1rem;
  background: #222;
  color: #fff;
  padding: 12px 16px;
  border-radius: 8px;
}
.logo { font-weight: 700; }
.links {
  display: flex;
  flex: 1;
  justify-content: center;
  gap: 1rem;
  list-style: none;
  padding: 0;
  margin: 0;
}
.links a { color: #fff; text-decoration: none; }
.links a:focus-visible,
.cta:focus-visible {
  outline: 3px solid #93c5fd;
  outline-offset: 3px;
}
.cta {
  background: #e63946;
  color: #fff;
  text-decoration: none;
  padding: 6px 12px;
  border-radius: 6px;
  font-weight: 600;
}
@media (max-width: 480px) {
  .nav {
    flex-direction: column;
    align-items: stretch;
  }

  .links {
    flex-wrap: wrap;
    justify-content: center;
  }

  .cta {
    text-align: center;
  }
}
